package com.yhk.aistudyplanner.ai.service;import com.yhk.aistudyplanner.ai.mapper.AiPlanningContextMapper;import com.yhk.aistudyplanner.ai.vo.AiPlanningContext;import com.yhk.aistudyplanner.task.entity.TaskStatus;import org.junit.jupiter.api.*;import org.junit.jupiter.api.extension.ExtendWith;import org.mockito.Mock;import org.mockito.junit.jupiter.MockitoExtension;import java.time.*;import java.util.*;import static org.junit.jupiter.api.Assertions.*;import static org.mockito.Mockito.*;
@ExtendWith(MockitoExtension.class) class AiPlanningContextServiceTest {@Mock AiPlanningContextMapper mapper;AiPlanningContextService service;static final LocalDate TODAY=LocalDate.of(2026,7,23);
 @BeforeEach void setUp(){service=new AiPlanningContextService(mapper,Clock.fixed(TODAY.atStartOfDay(ZoneId.of("Asia/Shanghai")).toInstant(),ZoneId.of("Asia/Shanghai")));}
 @Test void everyQueryUsesCurrentUserAndTextIsTruncated(){String longText="x".repeat(400);var task=new AiPlanningContext.TaskContext(1L,2L,"Java","#fff",null,null,"集合",longText,3,TaskStatus.TODO,60,TODAY,null);var record=new AiPlanningContext.RecordContext(2L,"Java",1L,"集合",TODAY.atTime(9,0),30,longText);when(mapper.subjects(9)).thenReturn(List.of());when(mapper.goals(9)).thenReturn(List.of());when(mapper.tasks(9,TODAY,TODAY.atStartOfDay())).thenReturn(List.of(task));when(mapper.summary(eq(9L),any(),any())).thenReturn(new AiPlanningContext.StudySummaryContext(30,1,1));when(mapper.subjectStudy(eq(9L),any(),any())).thenReturn(List.of());when(mapper.records(9)).thenReturn(List.of(record));var result=service.build(9,TODAY);assertEquals(300,result.tasks().get(0).description().length());assertEquals(300,result.recentRecords().get(0).feedback().length());verify(mapper).tasks(9,TODAY,TODAY.atStartOfDay());verify(mapper).records(9);}
}
